exercises.solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    if (n <= 0) {
        std::cout << "Invalid input\n";
        return 1;
    }

    int steps = 0;

    while (n != 1) {
        std::cout << n << '\n';
        if (n % 2 == 0)
            n /= 2;
        else
            n = n * 3 + 1;
        ++steps;
    }

    // print the final value
    std::cout << n << '\n';
    std::cout << "Steps: " << steps << '\n';
    return 0;
}

