exercises.solution_code:
#include <iostream>

void printRow(char grade, int count) {
    std::cout << grade << ": ";
    for (int i = 0; i < count; ++i)
        std::cout << '*';
    std::cout << '\n';
}

int main() {
    int a = 0, b = 0, c = 0, d = 0, f = 0;

    for (int i = 0; i < 10; ++i) {
        int score{};
        std::cin >> score;

        if      (score >= 90) ++a;
        else if (score >= 80) ++b;
        else if (score >= 70) ++c;
        else if (score >= 60) ++d;
        else                  ++f;
    }

    printRow('A', a);
    printRow('B', b);
    printRow('C', c);
    printRow('D', d);
    printRow('F', f);

    return 0;
}
